parameters.jsCode:
// Parse and summarize query results for audit logging.
const result = $input.item.json;
const events = result.events || [];

console.log(`Ledger query returned ${events.length} events`);

const summary = {
  total: events.length,
  event_types: [...new Set(events.map(e => e.event_type))],
  stream_keys: [...new Set(events.map(e => e.stream_key))],
  earliest: events.length > 0 ? events[0].created_at : null,
  latest: events.length > 0 ? events[events.length - 1].created_at : null,
  events,
};

return { json: summary };
